INSERT INTO public.violations (title, description, location_city, location_state, incident_date, status)
VALUES
  ('NYPD Officers Shove Protesters and Journalists During Manhattan March',
   'Video shows NYPD officers shoving and punching protesters on 5th Ave. NYC DOI report found systemic failures in NYPD protest response planning and execution.',
   'New York','New York','2020-06-04','pending'),
  ('Chicago CPD Fires Pepper Balls at Journalists on Michigan Avenue',
   'Multiple journalists with visible press credentials hit with pepper balls. RCFP condemned the incident. CPD spokesperson claimed journalists were too close to the line.',
   'Chicago','Illinois','2020-05-30','pending'),
  ('Atlanta APD Tases Two Spelman College Students in Their Car',
   'Taniyah Pilgrim and Messiah Young tased and dragged from vehicle while stuck in traffic during protests. Officers fired. Civil settlements reached.',
   'Atlanta','Georgia','2020-05-31','pending'),
  ('Minneapolis MPD Shoots Rubber Bullets at Family Standing on Their Own Porch',
   'Footage shows officers firing at a family including children standing on their porch and ordering them inside.',
   'Minneapolis','Minnesota','2020-05-30','pending'),
  ('Portland PPB Tear Gases Protesters Outside Federal Courthouse for 100+ Days',
   'Portland Police and federal agents used tear gas and munitions on protesters for over 100 consecutive nights. Multiple federal injunctions issued. ACLU-OR filed suit.',
   'Portland','Oregon','2020-07-01','pending'),
  ('Denver DPD Fires Rubber Bullets Causing 9 Serious Injuries',
   'DOJ investigation found Denver police fired rubber bullets, pepper balls, and tear gas at peaceful protesters. Nine suffered eye injuries. $14.3M settlement reached.',
   'Denver','Colorado','2020-05-30','pending'),
  ('Memphis MPD Fatal Beating of Tyre Nichols During Traffic Stop',
   'Tyre Nichols stopped for alleged traffic violation, beaten by SCORPION unit. Died three days later. Five officers charged with second-degree murder. DOJ opened investigation.',
   'Memphis','Tennessee','2023-01-07','pending'),
  ('Phoenix PD Points Guns at Family Including Toddler During Shoplifting Call',
   'Body camera shows officers pointing guns at Black family including a toddler. Officers cursed repeatedly. $1.5M settlement reached.',
   'Phoenix','Arizona','2019-06-14','pending'),
  ('Buffalo PD Pushes 75-Year-Old Martin Gugino to Pavement at Protest',
   'Footage shows Martin Gugino pushed to ground, suffering brain injury. Officers suspended with pay. Grand jury declined to indict.',
   'Buffalo','New York','2020-06-04','pending'),
  ('Philadelphia PPD Tear Gasses Protesters Trapped on I-676 Overpass',
   'Officers deployed tear gas on crowd trapped on a highway overpass with no means of exit. National Guard present. Pennsylvania AG investigated.',
   'Philadelphia','Pennsylvania','2020-06-01','pending'),
  ('Baltimore BPD Racial Profiling Under Zero Tolerance Policy',
   'DOJ found Baltimore PD made 300,000 pedestrian stops over 4 years, 95% resulting in no arrest. Disproportionately targeting Black residents. Federal consent decree entered.',
   'Baltimore','Maryland','2016-08-10','pending'),
  ('Detroit PD Wrongfully Arrests Innocent Man Using Faulty Facial Recognition',
   'Robert Williams arrested and held 30 hours based on faulty facial recognition. First published wrongful arrest by facial recognition in the US. ACLU lawsuit led to policy reforms.',
   'Detroit','Michigan','2020-01-09','pending'),
  ('Baton Rouge PD Arrests 102 Protesters Including National Lawyers Guild Legal Observers',
   'Following Alton Sterling shooting, 102 arrested at protest. NLG legal observers in green hats included in arrests. DOJ opened investigation.',
   'Baton Rouge','Louisiana','2016-07-10','pending'),
  ('Seattle SPD Fires Pepper Spray Into Crowd at Capitol Hill Protest',
   'Officers sprayed directly into crowd at CHOP boundary. Multiple injuries documented. City temporarily banned pepper spray for eight months before reversing.',
   'Seattle','Washington','2020-06-09','pending'),
  ('Austin APD Fires Bean Bags on Congress Ave Protest, Injuring 11',
   'Less-lethal munitions deployed on protest crowd, injuring 11 including bystanders. Council later passed reforms limiting crowd-control weapons.',
   'Austin','Texas','2020-05-31','pending'),
  ('Dallas PD Tear Gases Peaceful March on Margaret Hunt Hill Bridge',
   'Officers deployed tear gas and pepper spray on hundreds of peaceful marchers. Multiple journalists struck. Federal class action lawsuit followed.',
   'Dallas','Texas','2020-06-01','pending'),
  ('Miami PD Arrests Seven Credentialed Journalists During Protest Coverage',
   'Seven journalists with valid credentials arrested. Committee to Protect Journalists documented 18 press violations in Florida that week. All charges dropped.',
   'Miami','Florida','2020-05-31','pending'),
  ('Houston Police Arrest Street Preacher Near Courthouse for Recording',
   'Abraham Hamilton arrested while lawfully preaching near courthouse. First Amendment lawsuit filed and settled. Charges dropped.',
   'Houston','Texas','2022-08-15','pending'),
  ('Columbus CPD Fires Rubber Bullets Outside Police Headquarters',
   'Officers moved against protest crowd outside headquarters. Multiple injuries. Columbus City Council passed civilian review board legislation.',
   'Columbus','Ohio','2020-05-29','pending'),
  ('San Francisco PD Pins Unarmed Man in Prone Position for 9 Minutes',
   'Body camera footage shows officers restraining Dacari Spiers for 9 minutes prone. Medical examiner cited positional asphyxia as contributing factor.',
   'San Francisco','California','2021-09-14','pending'),
  ('Oakland PD Fires Rubber Bullets at Three Credentialed Journalists',
