  ('Jarrett Adams', NULL, 'Exoneree-turned-attorney. Wrongfully convicted at 17, served 10 years, became a civil rights lawyer. Advocates for wrongful conviction reform.', 'Illinois', ARRAY['wrongful_conviction','criminal_justice','youth_justice'], NULL, true, false),
  ('Phillip Agnew', NULL, 'Co-founder of Dream Defenders, a youth-led organization in Florida focused on dismantling the prison-industrial complex.', 'Florida', ARRAY['prison_abolition','youth_rights','racial_justice'], 'https://dreamdefenders.org', true, false),
  ('Bree Newsome Bass', NULL, 'Activist who climbed the South Carolina statehouse flagpole in 2015 to remove the Confederate battle flag. Continues work on racial equity.', 'North Carolina', ARRAY['racial_justice','Confederate_monuments','voting_rights'], NULL, true, false),
  ('Vanita Gupta', NULL, 'Former DOJ Assistant Attorney General for Civil Rights. Former president of Leadership Conference on Civil and Human Rights.', 'District of Columbia', ARRAY['civil_rights','police_reform','voting_rights'], 'https://civilrights.org', true, false),
  ('April Goggans', NULL, 'Core organizer for Black Lives Matter DC. Works at the intersection of racial justice, housing, and anti-poverty organizing.', 'District of Columbia', ARRAY['housing_rights','racial_justice','police_accountability'], NULL, true, false),
