-- 5. FORUM THREADS: 15 community discussion starters
-- =============================================================
INSERT INTO public.forum_threads (title, content, category, is_pinned)
VALUES
  ('PINNED: Community Rules and What This Forum Is For',
   'Welcome to the Civil Rights Hub community forum. This space is for sharing experiences, legal questions, organizing, and mutual support. Rules: Be respectful. No doxxing. No threats. Verify information before posting. Attorneys cannot give legal advice here — consult directly.',
   'announcements', true),
  ('How I Won My Police Misconduct Case Without a Lawyer',
   'Three years ago I was arrested at a peaceful protest. Could not afford an attorney. Here is the full story of how I filed a Section 1983 lawsuit, survived a motion to dismiss, and reached a settlement.',
   'experiences', false),
  ('FOIA Request Template That Actually Gets Body Cam Footage',
   'I have filed over 40 FOIA requests for body camera footage across 12 states. Here is the template language that gets results, what to do when they claim exemptions, and how to appeal denials.',
   'tools', false),
  ('What To Say (and Not Say) During a Traffic Stop',
   'Traffic stops are one of the most dangerous civil rights encounters. This post covers: what to say, what to never say, how to assert rights without escalating, and what to do after.',
   'know_your_rights', false),
  ('State-by-State: Which Civilian Review Boards Have Real Power?',
   'I spent six months researching every civilian police review board in the US. Most are toothless advisory bodies. A handful have real subpoena power and disciplinary authority. Here is my ranking.',
   'accountability', false),
  ('Resources for Indigenous Rights and Tribal Sovereignty',
   'Native and Indigenous communities face unique civil rights challenges that mainstream organizations often overlook. Sharing resources for tribal sovereignty, MMIW, treaty rights, and environmental justice.',
   'resources', false),
  ('How to Legally Livestream a Police Encounter',
   'Best apps, platforms, and settings for live streaming police encounters. What happens to your footage if your phone is seized. How to ensure footage is backed up automatically.',
   'know_your_rights', false),
  ('Looking for Pro Bono Attorney in Texas After Wrongful Arrest',
   'I was arrested and held for 18 hours with no charges filed. All charges eventually dropped but it is on my record and cost me my job. Looking for civil rights attorneys in DFW area.',
   'legal_help', false),
  ('First Amendment Auditors: Legal vs Illegal — What You Need to Know',
   'First Amendment audits are a growing movement testing whether public officials respect constitutional rights. Here is what is and is not protected, major settlements won, and how to stay safe.',
   'know_your_rights', false),
  ('Police Scanner Listening Guide for Activists and Journalists',
   'How to get started listening to police scanners. Best apps and hardware. How to cross-reference scanner traffic with incident reports. What to listen for during protests.',
   'tools', false),
  ('Mental Health Resources for Activists and Civil Rights Survivors',
   'Activism can be traumatic. This thread compiles free and low-cost mental health resources specifically for activists and civil rights victims, including therapists who specialize in racial trauma.',
   'resources', false),
  ('Breaking Down the DOJ Pattern and Practice Authority',
   'The DOJ Civil Rights Division can investigate police departments under 34 U.S.C. Section 12601. Here is how it works, what triggers an investigation, and which departments are under investigation.',
   'legal_education', false),
  ('Tenant Rights Emergency: Facing Eviction? Do This Right Now',
   'If you received an eviction notice: (1) do not panic, (2) count your days, (3) contact legal aid today, (4) know your state notice requirements, (5) assert your right to a hearing.',
   'emergency', false),
  ('Sharing Bail Fund Resources Nationwide',
   'Comprehensive list of bail funds by state and city. Most accept donations and several offer no-interest loans. If arrested at a protest, your first call after an attorney should be to a bail fund.',
   'resources', false),
  ('Organizers: Share Your City Recent Policy Wins',
   'Let us document the victories. Policy changes, settlements, officers held accountable, consent decrees. Post your city wins here. We need to see this movement making progress.',
   'organizing', false)
ON CONFLICT DO NOTHING;

