-- =============================================================
-- 7. POSTS: Starter knowledge posts for the social feed
-- =============================================================
INSERT INTO public.posts (content, post_type)
VALUES
  (E'🚨 KNOW YOUR RIGHTS: You have the right to film police in public spaces. The First Amendment protects recording law enforcement. If an officer tells you to stop filming, calmly say: "I am filming for my protection and yours." Do not block or interfere. #FilmThePolice #1stAmendment #KnowYourRights', 'text'),
  (E'📋 FOIA TIP: When requesting police body cam footage, be SPECIFIC. Include: date, time, location, officer badge number. Ask for ALL footage including interior vehicle cameras. Request in writing. They have 20 days under federal FOIA (state laws vary). #FOIA #PoliceAccountability', 'text'),
  (E'⚖️ The 4th Amendment protects you from unreasonable searches and seizures. Police generally need a warrant (signed by a judge), your voluntary consent (you can say no!), or probable cause plus exigent circumstances. If they search without any of these, that evidence may be suppressed. #4thAmendment', 'text'),
  (E'🔴 If you are stopped by police remember: (1) Stay calm, do not argue. (2) Ask: Am I free to go? (3) If not: I am invoking my right to remain silent. (4) Ask for an attorney immediately if arrested. (5) Document everything AFTER the encounter. #Miranda #KnowYourRights', 'text'),
  (E'📣 Section 1983 lawsuits are how citizens hold police accountable in federal court. You can sue individual officers AND municipalities for constitutional violations. The key challenge: qualified immunity. But recent rulings have narrowed that defense. Find a civil rights attorney. #Section1983', 'text'),
  (E'🗳️ VOTING RIGHTS: You have the right to a provisional ballot if your registration is questioned. Poll workers cannot ask about your citizenship status. Know your state current ID requirements before election day. #VotingRights #CivilRights', 'text'),
  (E'📸 LEGAL OBSERVERS: National Lawyers Guild trains and deploys legal observers at protests wearing green hats. They document police misconduct and support protesters. If you see a green hat they are there to help. Consider training to become one. #LegalObserver #ProtestRights', 'text'),
  (E'🏛️ Several major police departments are under federal consent decrees requiring reform: Chicago PD (2019), Baltimore PD (2017), Seattle PD (2012), Oakland PD (2003). Consent decrees mean federal judges are monitoring compliance. These are wins won by communities. #PoliceReform', 'text'),
  (E'🧠 KNOW THE DIFFERENCE: Terry stop vs Arrest. Terry stop: Brief detention on reasonable suspicion. Temporary. Some states require you to identify yourself. Arrest: Full custody, probable cause required, Miranda rights apply. Police often make Terry stops feel like arrests. #KnowYourRights', 'text'),
  (E'🎙️ PRESS FREEDOM: Journalists have the same First Amendment rights at protests as the general public. If you are filming as a journalist, clearly identify yourself. The Reporters Committee has a 24/7 legal defense hotline: 1-800-336-4243. #PressFreedom #1stAmendment', 'text')
ON CONFLICT DO NOTHING;

